mapper.select:
SELECT p.*, c.category_name, u.nickname, u.phone, u.email FROM t_product p LEFT JOIN t_category c ON p.category_id = c.id LEFT JOIN t_user u ON p.user_id = u.id
AND p.status = #{status}
AND p.category_id = #{categoryId}
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY p.create_time DESC

